"use client";
import React, { useMemo } from "react";

import { Breakpoint } from "@mui/material/styles";
import { styled } from "@mui/material/styles";
import { unstable_memoTheme as memoTheme } from "@mui/material/utils";

import type {
  DrawerConfig,
  EdgeSidebarVariant,
  EdgeSidebarVariantInput,
  PermanentConfig,
} from "./SharedEdgeSidebar";
import {
  EdgeSidebarRoot,
  internalCollapseSidebar,
  internalToggleSidebar,
} from "./SharedEdgeSidebar";
import { layoutAttrs } from "./layoutAttrs";
import { layoutClasses } from "./layoutClasses";

function applyDrawerStyles(params: DrawerConfig) {
  const { width = "300px", showHeader, withoutOverlay } = params || {};
  return {
    "--jun-ES-drawerWidth": "0px",
    ...(showHeader && {
      "--drawer-h": "calc(var(--jun-h) - var(--jun-H-h))",
      "&::before": {
        top: "var(--jun-H-h)",
      },
    }),
    ...(withoutOverlay && {
      "--drawer-h": "calc(var(--jun-h) - var(--jun-H-clip-h))",
      "&::before": {
        display: "none",
      },
    }),
    [`.${layoutClasses.Root}:has(&)`]: {
      "--jun-ES-variant": "var(--drawer)",
      [`.${layoutClasses.EdgeSidebarCollapser}`]: {
        display: "none",
      },
    },
    [`.${layoutClasses.Root}:has(&[${layoutAttrs.isDrawerOpen}])`]: {
      [`.${layoutClasses.EdgeDrawerTrigger} .${layoutClasses.EdgeDrawerClosedVisible}`]:
        {
          display: "none",
        },
    },
    [`.${layoutClasses.Root}:has(&:not([${layoutAttrs.isDrawerOpen}]))`]: {
      [`.${layoutClasses.EdgeDrawerTrigger} .${layoutClasses.EdgeDrawerOpenVisible}`]:
        {
          display: "none",
        },
    },
    [`&[${layoutAttrs.isDrawerOpen}], &[${layoutAttrs.isDrawerClosing}]`]: {
      "--jun-ES-drawerWidth": width,
    },
  };
}

function applyPermanentStyles(params: PermanentConfig) {
  const { width, collapsedWidth, visibility } = params || {};
  const defaultExpandConfig = {
    delay: "0s",
    shadow: "0 0 10px rgba(0,0,0,0.1)",
  };
  let expandConfig: undefined | typeof defaultExpandConfig;
  if ("hoverUncollapse" in params) {
    if (params.hoverUncollapse === true) {
      expandConfig = defaultExpandConfig;
    } else {
      expandConfig = params.hoverUncollapse as typeof defaultExpandConfig;
    }
  }
  return {
    "--jun-EC-shadow":
      "inset calc(-1 * var(--jun-ES-line-w)) 0px var(--jun-ES-line-color)",
    "--jun-EC-width": "var(--_permanentWidth, 0px)",
    "--_collapsed": "var(--collapsed)",
    "--_uncollapsed": "var(--uncollapsed)",
    [`.${layoutClasses.Root}:has(&)`]: {
      "--jun-ES-variant": "var(--permanent)",
      ...(width && {
        "--jun-ES-permanentWidth": width,
      }),
      ...(collapsedWidth && {
        "--jun-ES-collapsedWidth": collapsedWidth,
        [`.${layoutClasses.EdgeSidebarCollapser}`]: {
          display: "var(--display, inline-flex)",
          "--_sidebarCollapsed": "var(--collapsed, 1)",
          [`.${layoutClasses.EdgeCollapsedVisible}`]: {
            display: "var(--collapsed, inline-flex) var(--uncollapsed, none)",
          },
          [`.${layoutClasses.EdgeUncollapsedVisible}`]: {
            display: "var(--collapsed, none) var(--uncollapsed, inline-flex)",
          },
        },
      }),
      [`.${layoutClasses.EdgeDrawerTrigger}`]: {
        display: "none",
      },
    },
    ...(collapsedWidth && {
      /** Collapsible feature */
      [`.${layoutClasses.Root}:has(&[${layoutAttrs.isEdgeSidebarCollapsed}])`]:
        {
          "--jun-ES-collapsible": "var(--collapsed)",
        },
      [`.${layoutClasses.Root}:has(&[${layoutAttrs.isEdgeSidebarUncollapsed}])`]:
        {
          "--jun-ES-collapsible": "var(--uncollapsed)",
        },
    }),
    ...(visibility === "hidden" && {
      [`.${layoutClasses.Root}:has(>&)`]: {
        "--_permanentWidth": "0px",
      },
      [`& .${layoutClasses.EdgeSidebarContent}`]: {
        visibility: "hidden",
      },
    }),
    ...(visibility === "visible" && {
      [`.${layoutClasses.Root}:has(>&)`]: {
        "--_permanentWidth": `var(--uncollapsed, var(--jun-ES-permanentWidth))
                              var(--collapsed, var(--jun-ES-collapsedWidth, 0px))`,
      },
      [`& .${layoutClasses.EdgeSidebarContent}`]: {
        visibility:
          "var(--_drawer, hidden) var(--_permanent, visible)" as never,
      },
    }),
    ...(expandConfig && {
      [`&:has(.${layoutClasses.EdgeSidebarContent}:hover)`]: {
        "--_collapsed": "var(--__,)", // workaround to use fallback, Emotion strips out spaces if the value is " ".
        "--_uncollapsed": "var(--_)",
        [`& .${layoutClasses.SidebarRail}`]: {
          display: "none",
        },
      },
      [`& .${layoutClasses.EdgeSidebarContent}:hover`]: {
        "--jun-EC-width": "var(--jun-ES-permanentWidth)",
        "--jun-EC-delay": expandConfig.delay,
        "--jun-EC-shadow": `var(--_permanent, var(--uncollapsed, inset calc(-1 * var(--jun-ES-line-w)) 0 var(--jun-ES-line-color)) var(--collapsed, ${expandConfig.shadow}, inset calc(-1 * var(--jun-ES-line-w)) 0 var(--jun-ES-line-color)))`,
      },
    }),
  };
}

export function triggerEdgeCollapse(options: {
  event: React.MouseEvent;
  sidebarId?: string;
  state?: boolean;
  document?: Document | null;
}) {
  const { sidebarId } = options || {};
  let selector = `.${layoutClasses.EdgeSidebar}`;
  if (sidebarId) {
    selector = `#${sidebarId}`;
  }
  internalCollapseSidebar({ ...options, selector });
}

export function triggerEdgeDrawer(options?: {
  sidebarId?: string;
  state?: boolean;
  document?: Document | null;
}) {
  const { sidebarId } = options || {};
  let selector = `.${layoutClasses.EdgeSidebar}`;
  if (sidebarId) {
    selector = `#${sidebarId}`;
  }
  internalToggleSidebar({ ...options, selector });
}

interface EdgeSidebarOwnerState {
  variant?: Partial<Record<Breakpoint, EdgeSidebarVariant>>;
  permanentAutoCollapse?: Breakpoint;
}

interface EdgeSidebarProps {
  variant?: EdgeSidebarVariantInput;
  permanentAutoCollapse?: Breakpoint;
}

const StyledEdgeSidebar = styled(EdgeSidebarRoot, {
  name: "LayoutEdgeSidebar",
  slot: "root",
})<{
  ownerState: EdgeSidebarOwnerState;
}>(
  memoTheme(({ theme }) => ({
    [`.${layoutClasses.Root}:has(&)`]: {
      /** Root default settings */
      "--jun-ES-variant": "var(--permanent)",
      "--jun-ES-permanentWidth": "256px",
      "--jun-ES-collapsible": "var(--uncollapsed)",
      "--jun-ES-collapsedWidth": "0px",

      /** DO NOT OVERRIDE, internal variables */
      "--drawer": "var(--jun-ES-variant,)",
      "--permanent": "var(--jun-ES-variant,)",
      "--_permanentWidth": `var(--uncollapsed, var(--jun-ES-permanentWidth))
                            var(--collapsed, var(--jun-ES-collapsedWidth, 0px))`,
      "--collapsed": "var(--jun-ES-collapsible,)",
      "--uncollapsed": "var(--jun-ES-collapsible,)",
    },
    /** EdgeSidebar default settings */
    "--jun-ES-anchor": "var(--anchorLeft)",
    "--jun-EC-width": "var(--_permanentWidth, 0px)",
    "--_drawer": "var(--drawer)",
    "--_permanent": "var(--permanent)",
    "--_collapsed": "var(--collapsed)",
    "--_uncollapsed": "var(--uncollapsed)",
    gridArea: layoutClasses.EdgeSidebar,
    width: `var(--drawer, 0)
              var(--permanent, var(--_permanentWidth))`,
    borderColor: "var(--jun-ES-line-color)",
    [`&:not([${layoutAttrs.isDrawerOpen}], [${layoutAttrs.isDrawerClosing}])`]:
      {
        overflow: "var(--drawer, hidden)",
      },
    variants: [
      {
        props: ({ variant }: EdgeSidebarOwnerState) => !!variant,
        style: ({ variant }: Required<EdgeSidebarOwnerState>) => {
          const responsive: Record<string, unknown> = {};
          (Object.keys(variant) as Array<Breakpoint>)
            .sort(
              (a, b) =>
                theme.breakpoints.values[a] - theme.breakpoints.values[b],
            )
            .forEach((breakpoint) => {
              const variantTuple = variant[breakpoint];
              if (variantTuple) {
                const [variantName, params = {}] = variantTuple;
                const variantStyles = {
                  drawer: applyDrawerStyles,
                  permanent: applyPermanentStyles,
                }[variantName](params as never);
                if (breakpoint === "xs") {
                  Object.assign(responsive, variantStyles);
                } else {
                  responsive[theme.breakpoints.up(breakpoint)] = variantStyles;
                }
              }
            });
          return responsive;
        },
      },
      {
        props: ({ permanentAutoCollapse }: EdgeSidebarOwnerState) =>
          !!permanentAutoCollapse,
        style: ({
          permanentAutoCollapse,
        }: Required<EdgeSidebarOwnerState>) => ({
          [`.${layoutClasses.Root}:has(&) .${layoutClasses.EdgeSidebarCollapser}`]:
            {
              "--_autoCollapse": "1",
            },
          [theme.breakpoints.down(permanentAutoCollapse)]: {
            [`.${layoutClasses.Root}:has(&)`]: {
              "--jun-ES-collapsible": "var(--collapsed)",
            },
          },
          [theme.breakpoints.up(permanentAutoCollapse)]: {
            [`.${layoutClasses.Root}:has(&)`]: {
              "--jun-ES-collapsible": "var(--uncollapsed)",
            },
            [`.${layoutClasses.Root}:has(&) .${layoutClasses.EdgeSidebarCollapser}`]:
              {
                "--_in-autoCollapse": "1",
              },
          },
        }),
      },
    ],
  })),
);

const defaultVariant: EdgeSidebarVariant = ["permanent", { width: "256px" }];

const EdgeSidebar = React.forwardRef<
  HTMLDivElement,
  Omit<React.ComponentPropsWithoutRef<typeof StyledEdgeSidebar>, "ownerState"> &
    EdgeSidebarProps
>(function EdgeSidebar(
  { className, variant = defaultVariant, permanentAutoCollapse, ...props },
  ref,
) {
  const normalizedVariant = useMemo(
    () => (Array.isArray(variant) ? { xs: variant } : variant),
    [variant],
  );
  const ownerState = useMemo(
    () => ({
      variant: normalizedVariant,
      permanentAutoCollapse,
    }),
    [normalizedVariant, permanentAutoCollapse],
  );
  const hasWithoutOverlay = Object.values(normalizedVariant).some(
    (v) => v?.[0] === "drawer" && (v[1] as DrawerConfig)?.withoutOverlay,
  );
  return (
    <StyledEdgeSidebar
      ref={ref}
      className={`${layoutClasses.EdgeSidebar} ${className || ""}`}
      ownerState={ownerState}
      {...(hasWithoutOverlay && { "data-without-overlay": "" })}
      {...props}
    />
  );
});

export default EdgeSidebar;

"use client";
import React from "react";

import { triggerEdgeCollapse } from "./EdgeSidebar";
import { triggerEdgeCollapseRight } from "./EdgeSidebarRight";
import { layoutClasses } from "./layoutClasses";

interface EdgeSidebarCollapserProps {
  render: React.ReactElement<{
    className?: string;
    onClick?: React.MouseEventHandler<HTMLButtonElement>;
  }>;
  state?: boolean;
}

function EdgeSidebarCollapser({ render, state }: EdgeSidebarCollapserProps) {
  return React.cloneElement(render, {
    className: layoutClasses.EdgeSidebarCollapser,
    onClick: (event: React.MouseEvent<HTMLButtonElement>) => {
      const sidebar = event.currentTarget.closest<HTMLElement>(
        `.${layoutClasses.EdgeSidebar}, .${layoutClasses.EdgeSidebarRight}`,
      );
      const opts = {
        event,
        state,
        ...(sidebar?.id && { sidebarId: sidebar.id }),
      };
      if (sidebar?.classList.contains(layoutClasses.EdgeSidebarRight)) {
        triggerEdgeCollapseRight(opts);
      } else {
        triggerEdgeCollapse(opts);
      }
    },
  });
}

export default EdgeSidebarCollapser;

"use client";
import React from "react";
import { styled } from "@mui/material/styles";
import { layoutAttrs } from "./layoutAttrs";
import { layoutClasses } from "./layoutClasses";

const StyledEdgeSidebarContent = styled("div", {
  name: "LayoutEdgeSidebarContent",
  slot: "root",
})({
  /* configurable */
  background: "var(--EdgeSidebarContent-background)",
  boxShadow: "var(--jun-EC-shadow)",
  display: "flex",
  flexDirection: "column",
  flex: "1",
  padding: "0px",
  overflowX: "auto", // prevent horizontal content overflow
  "--jun-EC-delay": "0s",
  opacity: `var(--_drawer, var(--jun-ES-drawerOpen))
        var(--_permanent, 1)`,
  visibility: `var(--_drawer, hidden) var(--_permanent, visible)` as never,
  margin: "0px", // prevent user from customizing it
  position:
    "var(--_drawer, var(--drawer-pos)) var(--_permanent, relative)" as never,
  zIndex: "2",
  width:
    "var(--_drawer, var(--jun-ES-drawerWidth)) var(--_permanent, var(--jun-EC-width))",
  height: "var(--_drawer, var(--drawer-h))",
  top: "var(--_drawer, calc(var(--jun-h) - var(--drawer-h)))",
  overflowY: "var(--_drawer, auto)" as never,
  transition: `var(--tsn, var(--_drawer, opacity 0.3s, transform 0.3s)
               var(--_permanent, opacity 0.4s, width 0.3s var(--jun-EC-delay, 0s), transform 0.3s var(--jun-EC-delay, 0s), box-shadow 0.3s var(--jun-EC-delay, 0s)))`,
  transform: `var(--_drawer, var(--anchorLeft, translateX(calc((1 - var(--jun-ES-drawerOpen)) * -100%))) var(--anchorRight, translateX(calc(var(--jun-ES-drawerOpen) * -100%))))
              var(--_permanent, translateX(var(--jun-ES-permanentSlide, 0)))`,
  [`[${layoutAttrs.isEdgeSidebarContentHidden}] &`]: {
    visibility: "hidden",
    opacity: "0",
  },
  [`[${layoutAttrs.isDrawerOpen}] &, [${layoutAttrs.isDrawerClosing}] &`]: {
    visibility: "visible",
  },
  [`[${layoutAttrs.isDrawerClosing}] &`]: {
    transition: "var(--tsn, transform 0.3s, visibility 0.3s, opacity 0.3s)",
  },
});

const EdgeSidebarContent = React.forwardRef<
  HTMLDivElement,
  React.ComponentPropsWithoutRef<typeof StyledEdgeSidebarContent>
>(function EdgeSidebarContent({ className, ...props }, ref) {
  return (
    <StyledEdgeSidebarContent
      ref={ref}
      className={`${layoutClasses.EdgeSidebarContent} ${className || ""}`}
      {...props}
    />
  );
});

export default EdgeSidebarContent;

"use client";
import React, { useMemo } from "react";

import { Breakpoint } from "@mui/material/styles";
import { styled } from "@mui/material/styles";
import { unstable_memoTheme as memoTheme } from "@mui/material/utils";

import type {
  DrawerConfig,
  EdgeSidebarVariant,
  EdgeSidebarVariantInput,
  PermanentConfig,
} from "./SharedEdgeSidebar";
import {
  EdgeSidebarRoot,
  internalCollapseSidebar,
  internalToggleSidebar,
} from "./SharedEdgeSidebar";
import { layoutAttrs } from "./layoutAttrs";
import { layoutClasses } from "./layoutClasses";

function applyDrawerRightStyles(params: DrawerConfig) {
  const { width = "300px", showHeader, withoutOverlay } = params || {};
  return {
    "--jun-ES-drawerWidth": "0px",
    ...(showHeader && {
      "--drawer-h": "calc(var(--jun-h) - var(--jun-H-h))",
      "&::before": {
        top: "var(--jun-H-h)",
      },
    }),
    ...(withoutOverlay && {
      "--drawer-h": "calc(var(--jun-h) - var(--jun-H-clip-h))",
      "&::before": {
        display: "none",
      },
    }),
    [`.${layoutClasses.Root}:has(&)`]: {
      "--jun-ESR-variant": "var(--drawer-R)",
      [`.${layoutClasses.EdgeSidebarRightCollapser}`]: {
        display: "none",
      },
    },
    [`.${layoutClasses.Root}:has(&[${layoutAttrs.isDrawerOpen}])`]: {
      [`.${layoutClasses.EdgeDrawerTriggerRight} .${layoutClasses.EdgeDrawerClosedVisible}`]:
        {
          display: "none",
        },
    },
    [`.${layoutClasses.Root}:has(&:not([${layoutAttrs.isDrawerOpen}]))`]: {
      [`.${layoutClasses.EdgeDrawerTriggerRight} .${layoutClasses.EdgeDrawerOpenVisible}`]:
        {
          display: "none",
        },
    },
    [`&[${layoutAttrs.isDrawerOpen}], &[${layoutAttrs.isDrawerClosing}]`]: {
      "--jun-ES-drawerWidth": width,
    },
  };
}

function applyPermanentRightStyles(params: PermanentConfig) {
  const { width, collapsedWidth, visibility } = params;
  const defaultExpandConfig = {
    delay: "0.3s",
    shadow: "0 0 10px rgba(0,0,0,0.1)",
  };
  let expandConfig: undefined | typeof defaultExpandConfig;
  if ("hoverUncollapse" in params) {
    if (params.hoverUncollapse === true) {
      expandConfig = defaultExpandConfig;
    } else {
      expandConfig = params.hoverUncollapse as typeof defaultExpandConfig;
    }
  }
  return {
    "--jun-EC-shadow":
      "inset var(--jun-ES-line-w) 0px var(--jun-ES-line-color)",
    "--jun-EC-width": "var(--_permanentWidth-R, 0px)",
    "--_collapsed": "var(--collapsed-R)",
    "--_uncollapsed": "var(--uncollapsed-R)",
    [`.${layoutClasses.Root}:has(&)`]: {
      "--jun-ESR-variant": "var(--permanent-R)",
      ...(width && {
        "--jun-ESR-permanentWidth": width,
      }),
      ...(collapsedWidth && {
        "--jun-ESR-collapsedWidth": collapsedWidth,
        [`.${layoutClasses.EdgeSidebarRightCollapser}`]: {
          display: "var(--display, inline-flex)",
          "--_sidebarCollapsed": "var(--collapsed-R, 1)",
          [`.${layoutClasses.EdgeCollapsedVisible}`]: {
            display:
              "var(--collapsed-R, inline-flex) var(--uncollapsed-R, none)",
          },
          [`.${layoutClasses.EdgeUncollapsedVisible}`]: {
            display:
              "var(--collapsed-R, none) var(--uncollapsed-R, inline-flex)",
          },
        },
      }),
      [`.${layoutClasses.EdgeDrawerTriggerRight}`]: {
        display: "none",
      },
    },
    ...(collapsedWidth && {
      /** Collapsible feature */
      [`.${layoutClasses.Root}:has(&[${layoutAttrs.isEdgeSidebarCollapsed}])`]:
        {
          "--jun-ESR-collapsible": "var(--collapsed-R)",
        },
      [`.${layoutClasses.Root}:has(&[${layoutAttrs.isEdgeSidebarUncollapsed}])`]:
        {
          "--jun-ESR-collapsible": "var(--uncollapsed-R)",
        },
    }),
    ...(visibility === "hidden" && {
      [`.${layoutClasses.Root}:has(>&)`]: {
        "--_permanentWidth-R": "0px",
      },
      [`& .${layoutClasses.EdgeSidebarContent}`]: {
        visibility: "hidden",
      },
    }),
    ...(visibility === "visible" && {
      [`.${layoutClasses.Root}:has(>&)`]: {
        "--_permanentWidth-R": `var(--uncollapsed-R, var(--jun-ESR-permanentWidth))
                                var(--collapsed-R, var(--jun-ESR-collapsedWidth, 0px))`,
      },
      [`& .${layoutClasses.EdgeSidebarContent}`]: {
        visibility:
          "var(--_drawer, hidden) var(--_permanent, visible)" as never,
      },
    }),
    ...(expandConfig && {
      [`&:has(.${layoutClasses.EdgeSidebarContent}:hover)`]: {
        "--_collapsed": "var(--__,)", // workaround to use fallback, Emotion strips out spaces if the value is " ".
        "--_uncollapsed": "var(--_)",
        [`& .${layoutClasses.SidebarRail}`]: {
          display: "none",
        },
      },
      [`& .${layoutClasses.EdgeSidebarContent}:hover`]: {
        "--jun-EC-width": "var(--jun-ESR-permanentWidth)",
        "--jun-EC-delay": expandConfig.delay,
